const DATA={"NEGO": {"num": "1", "name": "Reshape government negotiations", "lead": "P", "levels": {"P": {"role": "the lead", "actor": "The BMZ and the Federal Foreign Office (AA), as institutions", "action": "Reshape the negotiations to be two-way by design; resolve the specific coordination breakdown the interviews document — in one recent round the talks were led by the BMZ while the partner delegation&#x27;s visas were handled separately by the Federal Foreign Office, the two processes worked against each other, and a partner minister broke off the process (interview 11); develop the BMZ&#x27;s negotiating posture in step with the Federal Foreign Office&#x27;s own emphasis on explicit interests — building on the interministerial coordination (<em>Ressortabstimmung</em>) that already exists — so that development cooperation comes to the table as a clear, well-prepared counterpart; resource the partner side&#x27;s preparation rather than assuming it; and mandate the country-by-country renegotiation of the framework and <em>TZ-Abkommen</em> layer (a political act involving the BMZ, the AA and partner governments). <em>Grounded in:</em> the visa-coordination failure and the accounts of negotiations that are &quot;scripted,&quot; &quot;top-down&quot; and &quot;dictated from Berlin&quot; (interviews 11, 15), and the description of agreements carrying &quot;at least forty years of tradition,&quot; in which &quot;the document … is already colonial&quot; (interview 12). This is the core lever: the negotiations are where donor steering of partner policy concentrates, so the decisive action is political.", "search": "Reshape the negotiations to be two-way by design; resolve the specific coordination", "empty": false}, "IS": {"role": "a substantive, co-equal role", "actor": "The boards and headquarters of the implementing organisations (GIZ, KfW, the political foundations), and their country directors", "action": "Reform the consultation templates and the framework-contract layer (the <em>Rahmenvertrag</em>) that these organisations administer; commission translation of the framework agreements into partners&#x27; working languages; and ask country directors to prepare each consultation as a genuine two-way exchange — convening joint preparatory meetings with partner ministries and shaping the agenda <em>with</em> the partner, not <em>for</em> them. <em>Grounded in:</em> the unchanged 1967 framework and the 1960s–70s technical-cooperation treaties, often unavailable in the partner&#x27;s language (interviews 12, 15), and the country director&#x27;s pivotal latitude over how a consultation is actually run. (Country directors belong here, with Higher Management, not at the senior-staff tier below.)", "search": "Reform the consultation templates and the framework-contract layer (the Rahmenvertrag) that these", "empty": false}, "M": {"role": "proactive support", "actor": "Senior in-country professionals below director level", "action": "Shape the substance of consultations through well-prepared input and informal channels; use language that does not talk down to the partner (&quot;from on high&quot; — <em>von oben herab</em>); actively look for moments of shared problem-naming, where a difficulty is framed as common to both sides (&quot;we have a big problem with that in Germany too … it is a shared concern&quot; — <em>da haben wir in Deutschland auch ein großes Problem … es ist ein gemeinsames Anliegen</em>); and put partner-side capacity constraints in writing so they inform the preparation. <em>Grounded in:</em> the constructive-practice accounts (interview 12) and the view that partners must be structurally enabled to act on their own interests (&quot;you have to stand up for yourself, otherwise no one will stand up for you&quot; — <em>man muss auch für sich gerade stehen, sonst wird keiner für dich stehen</em>, interview 15).", "search": "Shape the substance of consultations through well-prepared input and informal channels; use", "empty": false}, "Lo": {"role": "documentary", "actor": "Working-level staff, described by function", "action": "Document the costs of consultation failures — partner ministers dropping out, untranslated agreements, the gap between the script and the room — and route them upward, assembling the evidence base the redesign needs. <em>Grounded in:</em> the episodes practitioners describe (interviews 11, 12, 15).", "search": "Document the costs of consultation failures — partner ministers dropping out, untranslated", "empty": false}}}, "WORK": {"num": "2", "name": "Progression & protected reporting", "lead": "IS", "levels": {"P": {"role": "no role here", "actor": "", "action": "Grading, clearance, evaluation and reporting infrastructure are human-resources matters of each organisation; the BMZ cannot reach into them. <em>This node is deliberately empty.</em>", "search": "Grading, clearance, evaluation and reporting infrastructure are human-resources matters of each organisation;", "empty": true}, "IS": {"role": "the lead", "actor": "The headquarters and boards of the implementing organisations", "action": "Redesign clearance and grading so authority follows formal rank; revise the progression and evaluation instruments; build the shared definition of racist conduct and extend the whistleblower/sexual-misconduct channel to racism, with anonymity protection; and strengthen national-staff representation (contract security for elected representatives, and genuine involvement in the decisions and information that concern them). <em>Grounded in:</em> the signing-authority asymmetry (interview 02); the attrition of staff who &quot;are good at their work&quot; (interview 13); the dismissive &quot;too much Afrika&quot; register tied to a deficit view of national staff (interview 15); and the constrained representation forums (interviews 05, 09, 17, 02). This HR redesign is the core act.", "search": "Redesign clearance and grading so authority follows formal rank; revise the progression", "empty": false}, "M": {"role": "proactive support", "actor": "Senior in-country professionals below director level", "action": "Audit the signing/clearance flows in their own offices and publish what they find; refuse the deficit register (&quot;exaggerates,&quot; &quot;not exemplary&quot;) in the performance feedback they write; and recognise the informal mentoring that already happens.", "search": "Audit the signing/clearance flows in their own offices and publish what they", "empty": false}, "Lo": {"role": "documentary", "actor": "Working-level staff, described by function", "action": "Document the patterns through the existing representation forums; and senior national staff take on the informal mentoring that the companion peer-support recommendation would formalise.", "search": "Document the patterns through the existing representation forums; and senior national staff", "empty": false}}}, "LANG": {"num": "3", "name": "Bilingual communication", "lead": "IS", "levels": {"P": {"role": "a supporting but real role", "actor": "The development ministry (BMZ) and the Federal Foreign Office (AA)", "action": "Make language competence relevant to the partner context a requirement for report-receiving staff; endorse document-language norms that include partners&#x27; working languages; and specify the narrow set of texts where German is legally required. The ministry-side competence requirement is genuine leverage, because part of why reporting stays double-language is the receiving end.", "search": "Make language competence relevant to the partner context a requirement for report-receiving", "empty": false}, "IS": {"role": "the lead", "actor": "The headquarters and boards of the implementing organisations", "action": "Resource translation as an institutional workflow step rather than voluntary effort on top of a workload; issue a leadership directive (from the departmental leadership or executive board) that partner-language fluency is a hiring requirement where operationally necessary — applying to consultants too; and renegotiate and translate the bilateral framework agreements (the <em>TZ-Abkommen</em>) into partners&#x27; working languages. <em>Grounded in:</em> the explicit &quot;directive from above&quot; proposal and the framework-agreements-in-German problem (interview 15). The institutional cost-transfer is the core act; lead.", "search": "Resource translation as an institutional workflow step rather than voluntary effort on", "empty": false}, "M": {"role": "co-equal, because it can neutralise the default", "actor": "Senior in-country managers below director level", "action": "Institute bilingual reporting and conception within their projects now — this is the tier that can actually neutralise the default, as the variance in the corpus shows: where management already does it, the ceiling lifts. Document the personal translation burden carried by bilingual staff and route the case upward. <em>Grounded in:</em> the project-level variance where a good run of managers already runs bilingual reporting (interview 01 — exact passage to confirm); the diaspora adviser&#x27;s account of voluntary translation work (interview 17).", "search": "Institute bilingual reporting and conception within their projects now — this is", "empty": false}, "Lo": {"role": "documentation", "actor": "Working-level staff, described by function — the level where the documents are used, not designed", "action": "Bilingual staff document the translation work they currently carry; staff who do not work in German document the exclusion from information — the pattern where a German-only document with &quot;important information in it&quot; is shared without comment and &quot;half of the people cannot read it&quot; (interview 17).", "search": "Bilingual staff document the translation work they currently carry; staff who do", "empty": false}}}, "TERMS": {"num": "4", "name": "Consistent staff terms", "lead": "IS", "levels": {"P": {"role": "no role here", "actor": "", "action": "Staff terms and human resources sit entirely with each implementing organisation; the BMZ cannot reach into them. <em>This node is deliberately empty — and saying so plainly matters, so the recommendation reaches the right addressee.</em>", "search": "Staff terms and human resources sit entirely with each implementing organisation; the", "empty": true}, "IS": {"role": "the lead", "actor": "The headquarters and boards of the implementing organisations", "action": "Stop citing whichever legal framework lowers the cost; align the points that discretion allows (annual leave, maternity and parental protection); and reform the benchmarking protocol so the comparator organisations are chosen transparently, the methodology is published, and the result is applied to staff terms rather than selectively quoted. <em>Grounded in:</em> the account of &quot;a selective reference … when it suits them&quot; used to justify lower pay (interview 03), and national-staff representatives&#x27; description of a benchmark whose comparator sample was assembled to flatter — &quot;they go for those organisations that favour them&quot; (interview 09). This human-resources redesign is the core act.", "search": "Stop citing whichever legal framework lowers the cost; align the points that", "empty": false}, "M": {"role": "proactive support", "actor": "Senior in-country professionals below director level", "action": "Document specific instances of selective application and the composition of benchmark samples; and ask, in writing, for a reasoned justification whenever one framework is cited in one direction but not the other.", "search": "Document specific instances of selective application and the composition of benchmark samples;", "empty": false}, "Lo": {"role": "documentary", "actor": "Working-level staff, described by function", "action": "Document the pattern through the existing staff-representation forums and route it upward.", "search": "Document the pattern through the existing staff-representation forums and route it upward.", "empty": false}}}, "TIME": {"num": "5", "name": "Designated time & evaluable role", "lead": "M", "levels": {"P": {"role": "no role here", "actor": "", "action": "Evaluation criteria and job design are human-resources matters of each organisation; the BMZ cannot dictate them. <em>This node is deliberately empty.</em>", "search": "Evaluation criteria and job design are human-resources matters of each organisation; the", "empty": true}, "IS": {"role": "a substantive design role", "actor": "The headquarters and boards of the implementing organisations", "action": "Issue the mandate from above (the <em>Auftrag von oben</em>); make addressing colonial continuities a yearly goal in the annual-planning cycle; revise the relevant job descriptions and evaluation criteria to include it; reform the upward-feedback instrument; and specify who designs and evaluates the work. Substantive — but not where the work is carried.", "search": "Issue the mandate from above (the Auftrag von oben); make addressing colonial", "empty": false}, "M": {"role": "the lead", "actor": "Senior in-country professionals below director level", "action": "This is where the designated, evaluable practice actually lives: senior staff carve out and model the engagement work, push back on outdated template language, sustain the cohort-organising, and document the disincentive pattern in the upward-feedback instrument so that headquarters can fix it. <em>Grounded in:</em> the &quot;mandate from above&quot; proposal and the feedback-instrument account (interview 12); the voluntary, on-the-side initiative pattern (interviews 18, 17). The work is carried here; lead.", "search": "This is where the designated, evaluable practice actually lives: senior staff carve", "empty": false}, "Lo": {"role": "recognition and documentation", "actor": "Working-level staff, described by function", "action": "Have the informal cohort work recognised as legitimate organisational practice, and document the steady tax of extra effort it carries (interview 17).", "search": "Have the informal cohort work recognised as legitimate organisational practice, and document", "empty": false}}}, "PREP": {"num": "6", "name": "Preparation on both sides", "lead": "IS", "levels": {"P": {"role": "no role here", "actor": "", "action": "Curriculum and induction design sit with the implementing organisations and their academy; the BMZ does not run them. <em>This node is deliberately empty.</em>", "search": "Curriculum and induction design sit with the implementing organisations and their academy;", "empty": true}, "IS": {"role": "the lead", "actor": "The headquarters and boards of the implementing organisations, and the Academy for International Cooperation (AIZ)", "action": "Make a module on colonial continuities compulsory and recurring — at the same standard already applied to compliance and data-security training — and deliver it inside the existing AIZ pre-departure block, so a line manager&#x27;s rationing of work time cannot defeat it; build the parallel induction for national staff; specify who designs and evaluates the module; and raise trainer quality where it is weak. <em>Grounded in:</em> the account that the AIZ&#x27;s post-colonial modules are strong &quot;but … not mandatory whatsoever,&quot; set against the recurring compulsory compliance and data-security training (interview 02), and the partner-side endorsement of a historical grounding so that one knows &quot;what kind of institutions you are entering into&quot; (interview 08). Designing and mandating the curriculum is the core act.", "search": "Make a module on colonial continuities compulsory and recurring — at the", "empty": false}, "M": {"role": "proactive support", "actor": "Senior in-country professionals below director level", "action": "Run pilot pre-deployment seminars and parallel local-staff preparation at office level; and document the gap — a country briefing for outgoing staff, nothing comparable for incoming national staff (interview 17) — and route the case upward.", "search": "Run pilot pre-deployment seminars and parallel local-staff preparation at office level; and", "empty": false}, "Lo": {"role": "documentary", "actor": "Working-level staff, described by function", "action": "National and German staff document their own preparation gaps and submit them for an institutional response.", "search": "National and German staff document their own preparation gaps and submit them", "empty": false}}}, "PEER": {"num": "7", "name": "Peer support & representation", "lead": "Lo", "levels": {"P": {"role": "endorsement and cover", "actor": "The BMZ", "action": "Endorse peer-support spaces and staff networks as legitimate organisational practice with real benefits for retention and effectiveness; give them political cover so that, where staff-run diversity initiatives draw external political pressure, they meet an institutional commitment rather than an exposed individual. <em>Grounded in:</em> the general pattern (interview 18, de-identified) that such an initiative survived external political pressure only by securing leadership backing — with a documentable instance on the public record, independent of the interview (the AfD&#x27;s <em>Kleine Anfrage</em> on a federal staff network, BT-Drs. 19/20093, 2020). <em>Register: keep any reference to that pressure factual, on the public record, and at the level of the initiative — not personalised or partisan.</em>", "search": "Endorse peer-support spaces and staff networks as legitimate organisational practice with real", "empty": false}, "IS": {"role": "standing, resourcing, protection", "actor": "The headquarters and boards of the implementing organisations", "action": "Designate time and standing for the spaces; resource them; integrate the mentoring layer with the existing representation forum; and protect participants and elected representatives on fixed-term contracts, so that representing colleagues or raising a concern does not put a contract renewal at risk.", "search": "Designate time and standing for the spaces; resource them; integrate the mentoring", "empty": false}, "M": {"role": "instituting and mentoring", "actor": "Senior in-country professionals below director level", "action": "Institute the practice within their offices now; recognise existing informal local-staff peer groupings as legitimate; take on the senior-to-new mentoring role; and surface where contract precarity is silencing representatives so headquarters can address it.", "search": "Institute the practice within their offices now; recognise existing informal local-staff peer", "empty": false}, "Lo": {"role": "the lead", "actor": "Working-level national staff", "action": "The spaces originate and live here: local staff organise the cohorts themselves, and the elected representation forum is theirs. <em>Grounded in:</em> the cohort space that lets staff &quot;share experiences … so you don&#x27;t feel alone&quot; (interview 17); the grassroots founding of the Cultural Diversity Initiative by staff themselves (interview 15); and the bottom-up, volunteer origin of staff diversity initiatives more broadly (interview 18). <em>This is the bottom-up case: management and the political level grant standing and protection, but the practice originates and lives here; lead.</em>", "search": "The spaces originate and live here: local staff organise the cohorts themselves,", "empty": false}}}, "STRAT": {"num": "8", "name": "Strategic co-conception", "lead": "IS", "levels": {"P": {"role": "a supporting role", "actor": "The BMZ and the Federal Foreign Office (AA)", "action": "Endorse norms that make strategic documents accessible to partner-country teams; set the expectation, at BMZ level, that strategy formation includes consultation with the partner country; and keep this in step with the Federal Foreign Office&#x27;s own emphasis on interests, so the message reaching partners is consistent. This is endorsement and expectation-setting — important support, but not the core act.", "search": "Endorse norms that make strategic documents accessible to partner-country teams; set the", "empty": false}, "IS": {"role": "the lead", "actor": "The headquarters and boards of the implementing organisations, including country directors", "action": "Reform how strategy documents are shared, so national staff can see the reasoning; build national-staff consultation into concept development and into the annual steering committees and operational planning; adopt the peer agency&#x27;s inclusive practice as a required step in the workflow; and ask country directors to share the programme-level strategic logic with their teams. <em>Grounded in:</em> the contrast practitioners draw with a peer European agency, where the national professional receives the full strategic picture in advance and can shape a programme as it is designed — against the German experience of work &quot;dictated from Berlin&quot; and entered &quot;with no context&quot; (interviews 08, 15). This is where the lever sits.", "search": "Reform how strategy documents are shared, so national staff can see the", "empty": false}, "M": {"role": "proactive support", "actor": "Senior in-country professionals below director level", "action": "Within their own projects, bring national colleagues into the strategy-shaping conversations and pass on the reasoning they do have, so colleagues can engage partner ministries with it rather than be caught without it; where the reasoning sits further upstream, flag the gap so it can be closed. <em>Grounded in:</em> national staff who, at the ministry interface, were asked questions they could not answer because the strategic reasoning had not reached them (interview 02).", "search": "Within their own projects, bring national colleagues into the strategy-shaping conversations and", "empty": false}, "Lo": {"role": "documentary", "actor": "Working-level staff, described by function", "action": "Request access to strategic documents and to the moments where strategy is discussed, and document the pattern whereby such documents reach national staff only when it happens to suit management, rather than as a matter of course (interview 17), to build the case upward.", "search": "Request access to strategic documents and to the moments where strategy is", "empty": false}}}, "DIAS": {"num": "9", "name": "Diaspora integration", "lead": "P", "levels": {"P": {"role": "the lead", "actor": "The BMZ and senior leadership, as institutions", "action": "Revise the <em>TZ-FZ-Leitlinie</em> deployment definition so dual-nationals and diaspora practitioners are not routed out of posted roles; create the politically empowered diaspora consultative body (the <em>FORIM</em> model) and bring diaspora consultation into strategic foreign-policy design; and consolidate the lessons of existing diaspora programmes (MEG; WIDU) beyond their project lifespan. <em>Grounded in:</em> the recruitment accounts in which colleagues are asked to give up a partner-country citizenship, and the posted role is treated as one for someone who &quot;has to be blond and blue-eyed&quot; (interview 15). The deployment definition and the consultative body are political acts; lead.", "search": "Revise the TZ-FZ-Leitlinie deployment definition so dual-nationals and diaspora practitioners are not", "empty": false}, "IS": {"role": "a substantive, co-equal role", "actor": "The headquarters and boards of the implementing organisations, including country directors", "action": "Reform funding access by easing the registered-association (<em>e.V.</em>) and Westernised-structure requirements; reframe partnership so diaspora-led organisations are strategic partners rather than implementation contractors; and give standing to the existing informal headquarters networks of staff who have moved from national to international roles.", "search": "Reform funding access by easing the registered-association (e.V.) and Westernised-structure requirements; reframe", "empty": false}, "M": {"role": "proactive support", "actor": "Senior in-country professionals below director level", "action": "Position diaspora practitioners as strategic partners now, and bring diaspora-led organisations into country-level programme design as commissioning partners.", "search": "Position diaspora practitioners as strategic partners now, and bring diaspora-led organisations into", "empty": false}, "Lo": {"role": "more than documentary", "actor": "Working-level staff, described by function", "action": "Diaspora staff already inside the institution document the asymmetric-expertise pattern, contribute to self-selected cohort work, and record the informal mechanisms the recommendation would formalise — and they are also the population the recommendation would integrate, which is why their role here weighs more than documentation alone.", "search": "Diaspora staff already inside the institution document the asymmetric-expertise pattern, contribute to", "empty": false}}}, "EVAL": {"num": "10", "name": "Open & learning-oriented evaluation", "lead": "IS", "levels": {"P": {"role": "a supporting role", "actor": "The BMZ and the wider OECD-DAC venue", "action": "Advance the decolonial reform of the international evaluation criteria; resist the way the added &quot;coherence&quot; criterion reinforces established structures; and endorse norms under which partners help define what is evaluated. This is higher-policy support, not the core act — the criteria are set internationally.", "search": "Advance the decolonial reform of the international evaluation criteria; resist the way", "empty": false}, "IS": {"role": "the lead", "actor": "The headquarters and boards of the implementing organisations", "action": "Decide <em>who</em> evaluates: mandate mixed/tandem teams with national co-evaluators and a pathway to partner-led evaluation backed by training; require partner co-definition of the evaluation questions; adopt decolonial criteria alongside the DAC set; reframe the purpose toward learning and reciprocal accountability; and mainstream the complaint and feedback mechanisms so they are known and used. <em>Grounded in:</em> the institutional variance — church-based organisations already co-develop questions with partners, work in national-evaluator tandems, and even delegate evaluation budgets to partners with training provided, whereas the state organisation&#x27;s recent practice was &quot;top-down, deutsch&quot; (interview 19) — and the reframe of &quot;capacity&quot; from &quot;they don&#x27;t know evaluation&quot; to &quot;our bureaucracy is arcane and has to be learned&quot; (interview 19). This is the core act.", "search": "Decide who evaluates: mandate mixed/tandem teams with national co-evaluators and a pathway", "empty": false}, "M": {"role": "proactive support", "actor": "Senior in-country professionals below director level", "action": "Closer to partners and with more authority to mediate, they can license critical questions and run the tandem at project level. <em>Grounded in:</em> the seniors&#x27; proximity to partners (interview 19).", "search": "Closer to partners and with more authority to mediate, they can license", "empty": false}, "Lo": {"role": "more than documentary", "actor": "Working-level staff, described by function", "action": "Apply the <strong>counterpart principle</strong> — national staff and junior colleagues speaking with their counterparts and with the target group, so people can speak freely across steep local hierarchies — and surface what the praise-oriented reports leave out. <em>Grounded in:</em> the counterpart principle and the observation that critical points &quot;kommen nicht vor&quot; in reports that must &quot;die Erfolge zeigen, um wieder Gelder zu kriegen&quot; (interview 19); corroborated by the report-gaming account in interview 08.", "search": "Apply the counterpart principle — national staff and junior colleagues speaking with", "empty": false}}}}, ANCH={"NEGO": {"P": "Rec 1 - Political decision-making level", "IS": "Rec 1 - Higher Management", "M": "Rec 1 - Institutional Senior", "Lo": "Rec 1 - Operational / Working-level"}, "WORK": {"P": "Rec 2 - Political decision-making level", "IS": "Rec 2 - Higher Management", "M": "Rec 2 - Institutional Senior", "Lo": "Rec 2 - Operational / Working-level"}, "LANG": {"P": "Rec 3 - Political decision-making level", "IS": "Rec 3 - Higher Management", "M": "Rec 3 - Institutional Senior", "Lo": "Rec 3 - Operational / Working-level"}, "TERMS": {"P": "Rec 4 - Political decision-making level", "IS": "Rec 4 - Higher Management", "M": "Rec 4 - Institutional Senior", "Lo": "Rec 4 - Operational / Working-level"}, "TIME": {"P": "Rec 5 - Political decision-making level", "IS": "Rec 5 - Higher Management", "M": "Rec 5 - Institutional Senior", "Lo": "Rec 5 - Operational / Working-level"}, "PREP": {"P": "Rec 6 - Political decision-making level", "IS": "Rec 6 - Higher Management", "M": "Rec 6 - Institutional Senior", "Lo": "Rec 6 - Operational / Working-level"}, "PEER": {"P": "Rec 7 - Political decision-making level", "IS": "Rec 7 - Higher Management", "M": "Rec 7 - Institutional Senior", "Lo": "Rec 7 - Operational / Working-level"}, "STRAT": {"P": "Rec 8 - Political decision-making level", "IS": "Rec 8 - Higher Management", "M": "Rec 8 - Institutional Senior", "Lo": "Rec 8 - Operational / Working-level"}, "DIAS": {"P": "Rec 9 - Political decision-making level", "IS": "Rec 9 - Higher Management", "M": "Rec 9 - Institutional Senior", "Lo": "Rec 9 - Operational / Working-level"}, "EVAL": {"P": "Rec 10 - Political decision-making level", "IS": "Rec 10 - Higher Management", "M": "Rec 10 - Institutional Senior", "Lo": "Rec 10 - Operational / Working-level"}};
const LVLNAME={"P": "Political decision-making level", "IS": "Higher Management", "M": "Institutional Senior", "Lo": "Operational / Working-level"}, COL={"P": "#6a1f9c", "IS": "#b8123a", "M": "#c94800", "Lo": "#8a6a1f"}, PDFB64="";
const wrap=document.getElementById('pcwrap'), pop=document.getElementById('pop');
const reader=document.getElementById('reader');
let hideT=null, pinned=false;
function setFade(slug){wrap.querySelectorAll('.spindle,.node,.nodenum').forEach(el=>{const r=el.getAttribute('data-rec');el.classList.toggle('faded', !!slug && r!==slug);});}
function clearFade(){wrap.querySelectorAll('.faded').forEach(e=>e.classList.remove('faded'));}
function placePop(el){const pw=pop.offsetWidth,ph=pop.offsetHeight,r=el.getBoundingClientRect(),vw=innerWidth,vh=innerHeight,m=8;
  let left=r.left,top=r.bottom+10;
  if(top+ph>vh-m){top=Math.max(m,Math.min(r.top+r.height/2-ph/2,vh-ph-m));left=r.right+10;if(left+pw>vw-m)left=r.left-pw-10;}
  left=Math.max(m,Math.min(left,vw-pw-m));pop.style.left=left+'px';pop.style.top=Math.max(m,top)+'px';}
function showPop(slug,lv,el){clearTimeout(hideT);const d=DATA[slug],b=d.levels[lv];if(!b)return;const lead=d.lead===lv;
  pop.style.borderTopColor=COL[lv];
  pop.innerHTML=`<p class="lvl" style="color:${COL[lv]}">${LVLNAME[lv]}${lead?`<span class="leadtag" style="background:${COL[lv]}">LEADS HERE</span>`:''}</p>`+
   `<p class="role">${b.role}</p>`+(b.actor?`<p class="actor">${b.actor}</p>`:'')+`<p class="action">${b.action}</p>`+
   `<a class="rc" href="#" style="color:${COL[lv]}" data-slug="${slug}" data-lv="${lv}">Read in context →</a>`+
   `<span class="prodnote">pdf.js #search=${encodeURIComponent((ANCH[slug]||{})[lv]||'')}</span>`;
  pop.classList.add('show');placePop(el);setFade(slug);}
function scheduleHide(){hideT=setTimeout(()=>{if(!pinned){pop.classList.remove('show');clearFade();}},200);}
wrap.querySelectorAll('.node').forEach(n=>{const s=n.getAttribute('data-rec'),lv=n.getAttribute('data-level');
  n.addEventListener('mouseenter',()=>showPop(s,lv,n));n.addEventListener('focus',()=>showPop(s,lv,n));
  n.addEventListener('mouseleave',scheduleHide);n.addEventListener('blur',scheduleHide);
  n.addEventListener('click',e=>{e.preventDefault();openReader(s,lv);});
  n.addEventListener('keydown',e=>{if(e.key==='Enter'||e.key===' '){e.preventDefault();openReader(s,lv);}});});
wrap.querySelectorAll('.spindle').forEach(sp=>{const s=sp.getAttribute('data-rec'),lv=DATA[s].lead;
  sp.addEventListener('mouseenter',()=>showPop(s,lv,sp));sp.addEventListener('mouseleave',scheduleHide);
  sp.addEventListener('click',e=>{e.preventDefault();openReader(s,lv);});});
wrap.querySelectorAll('.recrow').forEach(r=>{const s=r.getAttribute('data-rec');
  r.addEventListener('mouseenter',()=>setFade(s));r.addEventListener('mouseleave',()=>{if(!pop.classList.contains('show'))clearFade();});
  r.addEventListener('click',()=>openReader(s,DATA[s].lead));
  r.addEventListener('keydown',e=>{if(e.key==='Enter'||e.key===' '){e.preventDefault();openReader(s,DATA[s].lead);}});});
pop.addEventListener('mouseenter',()=>{pinned=true;clearTimeout(hideT);});
pop.addEventListener('mouseleave',()=>{pinned=false;scheduleHide();});
pop.addEventListener('click',e=>{const a=e.target.closest('.rc');if(a){e.preventDefault();openReader(a.dataset.slug,a.dataset.lv);}});
addEventListener('keydown',e=>{if(e.key==='Escape'){reader.classList.remove('open');pop.classList.remove('show');clearFade();}});
document.getElementById('rclose').addEventListener('click',()=>reader.classList.remove('open'));
