let pdfReady=false,pdfTried=false,pdfFailed=false,pageInfos=[];
async function initPdf(){pdfTried=true;
  try{
    if(!window.pdfjsLib){throw new Error('pdfjsLib missing');}
    pdfjsLib.GlobalWorkerOptions.workerSrc='https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
    const raw=atob(PDFB64);const arr=new Uint8Array(raw.length);for(let i=0;i<raw.length;i++)arr[i]=raw.charCodeAt(i);
    const doc=await pdfjsLib.getDocument({data:arr}).promise;
    const cont=document.getElementById('pdfviewport');cont.innerHTML='';const scale=1.3;
    for(let p=1;p<=doc.numPages;p++){const page=await doc.getPage(p);const vp=page.getViewport({scale});
      const pd=document.createElement('div');pd.className='pdfpage';pd.style.width=vp.width+'px';pd.style.height=vp.height+'px';
      const cv=document.createElement('canvas');cv.width=vp.width;cv.height=vp.height;pd.appendChild(cv);
      const hl=document.createElement('div');hl.className='pdfhllayer';pd.appendChild(hl);cont.appendChild(pd);
      await page.render({canvasContext:cv.getContext('2d'),viewport:vp}).promise;
      const tc=await page.getTextContent();pageInfos.push({vp,hl,items:tc.items});}
    pdfReady=true;return true;
  }catch(e){console.warn('pdf init failed',e);pdfFailed=true;
    document.getElementById('pdfviewport').style.display='none';document.getElementById('htmlreader').style.display='block';return false;}
}
function pdfSearch(anchor){pageInfos.forEach(pi=>pi.hl.innerHTML='');
  for(const pi of pageInfos){for(const it of pi.items){if(it.str && anchor && it.str.indexOf(anchor)!==-1){
    const tx=pdfjsLib.Util.transform(pi.vp.transform,it.transform);const fh=Math.hypot(tx[2],tx[3]);
    const box=document.createElement('div');box.className='pdfhl';
    box.style.left=tx[4]+'px';box.style.top=(tx[5]-fh)+'px';box.style.width=(it.width*pi.vp.scale)+'px';box.style.height=(fh*1.3)+'px';
    pi.hl.appendChild(box);box.scrollIntoView({behavior:'smooth',block:'center'});return true;}}}
  return false;}
function htmlHL(slug,lv){const el=document.getElementById('read-'+slug+(lv?('-'+lv):''))||document.getElementById('read-'+slug);
  document.querySelectorAll('#htmlreader .hl').forEach(e=>e.classList.remove('hl'));
  if(el){el.scrollIntoView({behavior:'smooth',block:'center'});const blk=el.classList.contains('lvlblock')?el:el.querySelector('.lvlblock');if(blk){blk.classList.add('hl');setTimeout(()=>blk.classList.remove('hl'),3000);}}}
function openReader(slug,lv){reader.classList.add('open');const anchor=(ANCH[slug]||{})[lv];
  if(pdfReady){pdfSearch(anchor);}
  else if(pdfFailed){htmlHL(slug,lv);}
  else{htmlHL(slug,lv);/*until pdf ready*/ if(!pdfTried){/*safety*/}}
}
// kick off pdf render on load
window.addEventListener('load',()=>{ if(window.pdfjsLib) initPdf(); else {pdfFailed=true;document.getElementById('pdfviewport').style.display='none';document.getElementById('htmlreader').style.display='block';} });